#include<cstdio>
#include<cmath>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
char buf[1<<21],*p1=buf,*p2=buf;
typedef long long LL;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline LL gcd(const LL&x,const LL&y){return y?gcd(y,x%y):x;}
int main()
{
	for(int T=read();T;--T)
	{
		LL x=read(),z=read();
		if(z%x!=0){puts("-1");continue;}
		z/=x;LL G,tmp=std::sqrt(G=gcd(x*x,z));
		if(tmp*tmp!=G){puts("-1");continue;}
		printf("%lld\n",z/tmp);
	}
}
